import { readFileSync } from 'node:fs'
import { Exa } from 'exa-js'

/** Create an Exa client instance. Requires EXA_API_KEY env var. */
export function createClient(): Exa {
  return new Exa()
}

/** Require a CLI argument, exit with error if missing. */
export function requireArg(value: string | undefined, name: string): string {
  if (!value) {
    console.error(`Error: ${name} is required`)
    process.exit(1)
  }
  return value
}

/** Execute an async API call, print JSON result, exit on error. */
export async function executeAndPrint<T>(apiCall: () => Promise<T>): Promise<void> {
  try {
    const result = await apiCall()
    console.log(JSON.stringify(result, null, 2))
  } catch (err) {
    handleError(err)
  }
}

/**
 * Show help text extracted from the JSDoc comment at the top of a script file.
 * Reads lines starting with " * " until " * /" is found.
 */
export function showHelp(scriptUrl: string): void {
  const lines: string[] = []
  const src = readFileSync(new URL(scriptUrl), 'utf8')
  for (const line of src.split('\n')) {
    if (line.startsWith(' * ') || line.startsWith(' */')) {
      if (line.startsWith(' */')) break
      lines.push(line.slice(3))
    }
  }
  console.log(lines.join('\n'))
  process.exit(0)
}

/**
 * Ensure EXA_API_KEY is set. Exits with an error message if not.
 */
export function requireApiKey(): void {
  if (!process.env.EXA_API_KEY) {
    console.error('Error: EXA_API_KEY environment variable is required.')
    console.error('Get one at: https://dashboard.exa.ai/api-keys')
    process.exit(1)
  }
}

/**
 * Parse CLI args: show help if --help or no args, return query and options.
 */
export function parseArgs(scriptUrl: string): { query: string; opts: Record<string, unknown> } {
  const args = process.argv.slice(2)

  if (args.includes('--help') || args.length === 0) {
    showHelp(scriptUrl)
  }

  const query = requireArg(args[0], 'query')
  const opts: Record<string, unknown> = args[1]
    ? (JSON.parse(args[1]) as Record<string, unknown>)
    : {}

  return { query, opts }
}

/**
 * Standardized error handler for all exa scripts.
 */
export function handleError(err: unknown): never {
  console.error(`Error: ${(err as Error).message}`)
  process.exit(1)
}

/**
 * Pick allowed keys from an options object, skipping undefined values.
 */
export function filterOptions(
  opts: Record<string, unknown>,
  keys: readonly string[],
): Record<string, unknown> {
  const filtered: Record<string, unknown> = {}
  for (const key of keys) {
    if (opts[key] !== undefined) filtered[key] = opts[key]
  }
  return filtered
}

/**
 * Build contents options from text/highlights/summary fields.
 */
export function buildContentsOptions(opts: Record<string, unknown>): Record<string, unknown> {
  let contentsOpts: Record<string, unknown> = {}
  if (opts.text === true) contentsOpts.text = true
  else if (typeof opts.text === 'object') contentsOpts.text = opts.text
  if (opts.highlights === true) contentsOpts.highlights = true
  else if (typeof opts.highlights === 'object') contentsOpts.highlights = opts.highlights
  if (opts.summary === true) contentsOpts.summary = true
  else if (typeof opts.summary === 'object') contentsOpts.summary = opts.summary
  if (typeof opts.contents === 'object')
    contentsOpts = { ...contentsOpts, ...(opts.contents as Record<string, unknown>) }
  return contentsOpts
}

#!/usr/bin/env tsx
/**
 * Exa answer — get AI-generated answers with citations.
 *
 * Usage:
 *   tsx scripts/answer.ts <query> [options-json]
 *   tsx scripts/answer.ts --help
 *
 * Options JSON (all optional):
 *   {
 *     "text": true,              // include full text in citation results
 *     "model": "exa",            // "exa" (default)
 *     "systemPrompt": "...",     // guide the LLM behavior
 *     "outputSchema": {},        // JSON Schema for structured output
 *     "stream": false,           // stream chunks to stdout
 *     "userLocation": "US"
 *   }
 *
 * Environment:
 *   EXA_API_KEY — required
 *
 * Examples:
 *   tsx scripts/answer.ts "What is the latest Next.js version?"
 *   tsx scripts/answer.ts "Compare React and Vue" '{"text":true}'
 *   tsx scripts/answer.ts "SpaceX valuation" '{"model":"exa","stream":true}'
 *   tsx scripts/answer.ts "List top 3 ORMs" '{"outputSchema":{"type":"object","properties":{"items":{"type":"array","items":{"type":"string"}}}}}'
 */

import { parseArgs, requireApiKey, handleError, filterOptions, createClient } from './lib/common.js'

const { query, opts } = parseArgs(import.meta.url)
requireApiKey()

const exa = createClient()

const answerOpts = filterOptions(opts, [
  'text',
  'model',
  'systemPrompt',
  'outputSchema',
  'userLocation',
])

try {
  if (opts.stream) {
    // Streaming mode — write chunks as they arrive
    for await (const chunk of exa.streamAnswer(query, answerOpts)) {
      const typedChunk = chunk as { content?: string; citations?: unknown }
      if (typedChunk.content) process.stdout.write(typedChunk.content)
      if (typedChunk.citations) {
        process.stdout.write('\n')
        console.log(JSON.stringify({ citations: typedChunk.citations }, null, 2))
      }
    }
    process.stdout.write('\n')
  } else {
    const result = await exa.answer(query, answerOpts)
    console.log(JSON.stringify(result, null, 2))
  }
} catch (err) {
  handleError(err)
}

#!/usr/bin/env tsx
/**
 * Exa get contents — retrieve page contents by URL.
 *
 * Usage:
 *   tsx scripts/contents.ts <url-or-urls-json> [options-json]
 *   tsx scripts/contents.ts --help
 *
 * First argument: a single URL string, or a JSON array of URLs.
 *
 * Options JSON (all optional):
 *   {
 *     "text": true,                         // or { "maxCharacters": 5000, "includeHtmlTags": false }
 *     "highlights": true,                   // or { "query": "AI", "numSentences": 3 }
 *     "summary": true,                      // or { "query": "summarize pricing" }
 *     "livecrawl": "auto",                  // "never"|"fallback"|"always"|"auto"|"preferred"
 *     "livecrawlTimeout": 10000,             // timeout in ms for live crawl
 *     "maxAgeHours": 168,                   // 0 = always fresh, -1 = cache only
 *     "filterEmptyResults": true,
 *     "subpages": 3,
 *     "subpageTarget": "pricing"
 *   }
 *
 * Environment:
 *   EXA_API_KEY — required
 *
 * Examples:
 *   tsx scripts/contents.ts "https://example.com/article"
 *   tsx scripts/contents.ts "https://example.com" '{"text":{"maxCharacters":2000}}'
 *   tsx scripts/contents.ts '["https://a.com","https://b.com"]' '{"text":true,"highlights":true}'
 */

import {
  parseArgs,
  requireApiKey,
  filterOptions,
  createClient,
  executeAndPrint,
} from './lib/common.js'

const { query: urlArg, opts: rawOpts } = parseArgs(import.meta.url)

let urls: string | string[] = urlArg
try {
  urls = JSON.parse(urlArg) as string[]
} catch {
  // Single URL string — keep as-is
}

const opts: Record<string, unknown> = Object.keys(rawOpts).length > 0 ? rawOpts : { text: true }

requireApiKey()

const exa = createClient()

const contentsOpts = filterOptions(opts, [
  'text',
  'highlights',
  'summary',
  'livecrawl',
  'livecrawlTimeout',
  'maxAgeHours',
  'filterEmptyResults',
  'subpages',
  'subpageTarget',
])

await executeAndPrint(async () => {
  return await exa.getContents(urls, contentsOpts)
})

#!/usr/bin/env tsx
/**
 * Exa research — create and manage deep research tasks.
 *
 * Usage:
 *   tsx scripts/research.ts create <instructions> [options-json]
 *   tsx scripts/research.ts get <research-id> [options-json]
 *   tsx scripts/research.ts poll <research-id> [options-json]
 *   tsx scripts/research.ts list [options-json]
 *   tsx scripts/research.ts run <instructions> [options-json]
 *   tsx scripts/research.ts --help
 *
 * Subcommands:
 *   create   — Start a new research task (returns immediately with researchId)
 *   get      — Get the current status/result of a research task
 *   poll     — Poll an existing task until finished (blocks until complete)
 *   list     — List research tasks
 *   run      — Create + poll in one step (convenience)
 *
 * Options JSON for create/run:
 *   {
 *     "model": "exa-research-fast",   // "exa-research-fast"|"exa-research"|"exa-research-pro"
 *     "outputSchema": {}              // JSON Schema for structured output
 *   }
 *
 * Options JSON for get:
 *   {
 *     "stream": false,                // stream SSE events
 *     "events": false                 // include event log
 *   }
 *
 * Options JSON for poll:
 *   {
 *     "pollInterval": 1000,           // ms between polls (default 1000)
 *     "timeoutMs": 600000,            // max wait time (default 10 min)
 *     "events": false
 *   }
 *
 * Options JSON for list:
 *   {
 *     "limit": 10,
 *     "cursor": "..."
 *   }
 *
 * Environment:
 *   EXA_API_KEY — required
 *
 * Examples:
 *   tsx scripts/research.ts create "Research the latest AI developments"
 *   tsx scripts/research.ts get "a1b2c3d4-e5f6-7890-abcd-ef1234567890"
 *   tsx scripts/research.ts run "What is SpaceX's latest valuation?" '{"model":"exa-research-pro"}'
 *   tsx scripts/research.ts list '{"limit":5}'
 */

import {
  showHelp,
  requireApiKey,
  handleError,
  requireArg,
  createClient,
  executeAndPrint,
} from './lib/common.js'

// research.ts has a subcommand pattern: parseArgs assumes args[1] is JSON opts,
// which conflicts with create/run where args[1] is instructions text. Use
// showHelp directly and index process.argv by position instead.
if (process.argv.includes('--help') || process.argv.length <= 2) {
  showHelp(import.meta.url)
}

const subcommand = process.argv[2]
const arg1 = process.argv[3]

requireApiKey()

const exa = createClient()

try {
  switch (subcommand) {
    case 'create': {
      const instructions = requireArg(arg1, 'instructions')
      const opts: Record<string, unknown> = process.argv[4]
        ? (JSON.parse(process.argv[4]) as Record<string, unknown>)
        : {}
      await executeAndPrint(async () =>
        exa.research.create({
          instructions,
          model:
            (opts.model as 'exa-research-fast' | 'exa-research' | 'exa-research-pro') ?? undefined,
          outputSchema: (opts.outputSchema as Record<string, unknown>) ?? undefined,
        }),
      )
      break
    }

    case 'get': {
      const researchId = requireArg(arg1, 'research-id')
      const opts: Record<string, unknown> = process.argv[4]
        ? (JSON.parse(process.argv[4]) as Record<string, unknown>)
        : {}
      if (opts.stream) {
        const streamResult = await exa.research.get(researchId, { stream: true, ...opts })
        for await (const event of streamResult) {
          process.stdout.write(JSON.stringify(event) + '\n')
        }
      } else {
        await executeAndPrint(async () => exa.research.get(researchId, opts))
      }
      break
    }

    case 'poll': {
      const researchId = requireArg(arg1, 'research-id')
      const opts: Record<string, unknown> = process.argv[4]
        ? (JSON.parse(process.argv[4]) as Record<string, unknown>)
        : {}
      await executeAndPrint(async () => exa.research.pollUntilFinished(researchId, opts))
      break
    }

    case 'run': {
      const instructions = requireArg(arg1, 'instructions')
      const opts: Record<string, unknown> = process.argv[4]
        ? (JSON.parse(process.argv[4]) as Record<string, unknown>)
        : {}
      const created = await exa.research.create({
        instructions,
        model:
          (opts.model as 'exa-research-fast' | 'exa-research' | 'exa-research-pro') ?? undefined,
        outputSchema: (opts.outputSchema as Record<string, unknown>) ?? undefined,
      })
      const createdTyped = created as { researchId: string }
      console.error(`Research task created: ${createdTyped.researchId} — polling...`)
      await executeAndPrint(async () =>
        exa.research.pollUntilFinished(createdTyped.researchId, {
          pollInterval: (opts.pollInterval as number) || 2000,
          timeoutMs: (opts.timeoutMs as number) || 600000,
          events: opts.events as boolean | undefined,
        }),
      )
      break
    }

    case 'list': {
      const opts: Record<string, unknown> = arg1
        ? (JSON.parse(arg1) as Record<string, unknown>)
        : {}
      await executeAndPrint(async () => exa.research.list(opts))
      break
    }

    default:
      console.error(`Error: Unknown subcommand "${subcommand}".`)
      console.error('Valid subcommands: create, get, poll, list, run')
      process.exit(1)
  }
} catch (err) {
  handleError(err)
}

import { describe, it } from 'node:test'
import assert from 'node:assert/strict'
import { spawnSync } from 'node:child_process'
import path from 'node:path'
import { fileURLToPath } from 'node:url'

import { requireArg } from '../lib/common.js'
import { filterOptions } from '../lib/common.js'
import { buildContentsOptions } from '../lib/common.js'

const __dirname = path.dirname(fileURLToPath(import.meta.url))

const TSX = path.join(__dirname, '..', '..', '..', '..', 'node_modules', '.bin', 'tsx')
const COMMON = path.join(__dirname, '..', 'lib', 'common.ts')

function runInline(
  code: string,
  env: Record<string, string | undefined> = {},
): { status: number; stdout: string; stderr: string } {
  const result = spawnSync(TSX, ['--eval', code], {
    encoding: 'utf8',
    env: { ...process.env, ...env },
  })
  return {
    status: result.status ?? -1,
    stdout: result.stdout ?? '',
    stderr: result.stderr ?? '',
  }
}

// ---------------------------------------------------------------------------
// requireArg
// ---------------------------------------------------------------------------

describe('requireArg: returns value when provided', () => {
  it('returns the string when value is present', () => {
    const result = requireArg('hello', 'test')
    assert.strictEqual(result, 'hello')
  })

  it('returns an empty-but-truthy string value', () => {
    const result = requireArg('x', 'name')
    assert.strictEqual(result, 'x')
  })
})

describe('requireArg: exits when value is undefined', () => {
  it('process exits with code 1 when value is undefined', () => {
    const result = runInline(
      `import { requireArg } from '${COMMON}'; requireArg(undefined, 'testarg');`,
    )
    assert.strictEqual(result.status, 1, `expected exit 1, got ${result.status}\n${result.stderr}`)
  })

  it('prints error message to stderr when value is undefined', () => {
    const result = runInline(
      `import { requireArg } from '${COMMON}'; requireArg(undefined, 'myarg');`,
    )
    assert.ok(result.stderr.includes('myarg'), `expected "myarg" in stderr:\n${result.stderr}`)
  })
})

// ---------------------------------------------------------------------------
// filterOptions
// ---------------------------------------------------------------------------

describe('filterOptions: picks specified keys', () => {
  it('returns only the keys listed in the keys array', () => {
    const opts = { a: 1, b: 2, c: 3 }
    const result = filterOptions(opts, ['a', 'c'])
    assert.deepStrictEqual(result, { a: 1, c: 3 })
  })

  it('does not include keys absent from the keys array', () => {
    const opts = { a: 1, b: 2 }
    const result = filterOptions(opts, ['a'])
    assert.ok(!('b' in result), 'result must not include key "b"')
  })
})

describe('filterOptions: skips undefined values', () => {
  it('omits keys whose value is undefined', () => {
    const opts: Record<string, unknown> = { a: 1, b: undefined }
    const result = filterOptions(opts, ['a', 'b'])
    assert.deepStrictEqual(result, { a: 1 })
    assert.ok(!('b' in result), '"b" with undefined value must be omitted')
  })

  it('keeps keys whose value is null or 0 (only undefined is skipped)', () => {
    const opts: Record<string, unknown> = { a: null, b: 0, c: false }
    const result = filterOptions(opts, ['a', 'b', 'c'])
    assert.ok('a' in result, '"a" with null value must be kept')
    assert.ok('b' in result, '"b" with 0 value must be kept')
    assert.ok('c' in result, '"c" with false value must be kept')
  })
})

describe('filterOptions: returns empty when no keys match', () => {
  it('returns {} when none of the specified keys exist in opts', () => {
    const opts = { x: 1, y: 2 }
    const result = filterOptions(opts, ['a', 'b'])
    assert.deepStrictEqual(result, {})
  })

  it('returns {} when opts is empty', () => {
    const result = filterOptions({}, ['a', 'b'])
    assert.deepStrictEqual(result, {})
  })
})

// ---------------------------------------------------------------------------
// buildContentsOptions
// ---------------------------------------------------------------------------

describe('buildContentsOptions: text: true', () => {
  it('sets text: true in output when opts.text is true', () => {
    const result = buildContentsOptions({ text: true })
    assert.deepStrictEqual(result, { text: true })
  })
})

describe('buildContentsOptions: highlights: true', () => {
  it('sets highlights: true in output when opts.highlights is true', () => {
    const result = buildContentsOptions({ highlights: true })
    assert.deepStrictEqual(result, { highlights: true })
  })
})

describe('buildContentsOptions: summary: true', () => {
  it('sets summary: true in output when opts.summary is true', () => {
    const result = buildContentsOptions({ summary: true })
    assert.deepStrictEqual(result, { summary: true })
  })
})

describe('buildContentsOptions: empty opts returns empty object', () => {
  it('returns {} when no relevant keys are present', () => {
    const result = buildContentsOptions({})
    assert.deepStrictEqual(result, {})
  })

  it('returns {} when opts only has irrelevant keys', () => {
    const result = buildContentsOptions({ numResults: 5, query: 'foo' })
    assert.deepStrictEqual(result, {})
  })
})

describe('buildContentsOptions: text as object with maxCharacters', () => {
  it('passes text object through when opts.text is an object', () => {
    const textObj = { maxCharacters: 500 }
    const result = buildContentsOptions({ text: textObj })
    assert.deepStrictEqual(result, { text: textObj })
  })
})

describe('buildContentsOptions: contents object merges into result', () => {
  it('merges opts.contents object fields into result', () => {
    const result = buildContentsOptions({ contents: { text: true, highlights: true } })
    assert.ok('text' in result, 'merged text from contents')
    assert.ok('highlights' in result, 'merged highlights from contents')
  })
})

// ---------------------------------------------------------------------------
// handleError
// ---------------------------------------------------------------------------

describe('handleError: exits with code 1', () => {
  it('process exits with code 1 when handleError is called', () => {
    const result = runInline(
      `import { handleError } from '${COMMON}'; handleError(new Error('boom'));`,
    )
    assert.strictEqual(result.status, 1, `expected exit 1, got ${result.status}\n${result.stderr}`)
  })

  it('prints error message to stderr', () => {
    const result = runInline(
      `import { handleError } from '${COMMON}'; handleError(new Error('test-error-message'));`,
    )
    assert.ok(
      result.stderr.includes('test-error-message'),
      `expected "test-error-message" in stderr:\n${result.stderr}`,
    )
  })
})

// ---------------------------------------------------------------------------
// requireApiKey
// ---------------------------------------------------------------------------

describe('requireApiKey: exits when EXA_API_KEY is missing', () => {
  it('process exits with code 1 when EXA_API_KEY is not set', () => {
    const result = runInline(`import { requireApiKey } from '${COMMON}'; requireApiKey();`, {
      EXA_API_KEY: undefined,
    })
    assert.strictEqual(result.status, 1, `expected exit 1, got ${result.status}\n${result.stderr}`)
  })

  it('prints error message to stderr when EXA_API_KEY is missing', () => {
    const result = runInline(`import { requireApiKey } from '${COMMON}'; requireApiKey();`, {
      EXA_API_KEY: undefined,
    })
    assert.ok(
      result.stderr.includes('EXA_API_KEY'),
      `expected "EXA_API_KEY" in stderr:\n${result.stderr}`,
    )
  })
})

describe('requireApiKey: succeeds when EXA_API_KEY is set', () => {
  it('process exits with code 0 when EXA_API_KEY is set', () => {
    const result = runInline(`import { requireApiKey } from '${COMMON}'; requireApiKey();`, {
      EXA_API_KEY: 'test-api-key-abc123',
    })
    assert.strictEqual(result.status, 0, `expected exit 0, got ${result.status}\n${result.stderr}`)
  })
})

import { describe, it } from 'node:test'
import assert from 'node:assert/strict'
import { readFileSync } from 'node:fs'
import { resolve, dirname } from 'node:path'
import { fileURLToPath } from 'node:url'

const __dirname = dirname(fileURLToPath(import.meta.url))

describe('refactor: contents.ts uses common.ts helpers', () => {
  it('contents.ts does not manually parse process.argv', () => {
    const src = readFileSync(resolve(__dirname, '../contents.ts'), 'utf8')
    assert.ok(
      !src.includes('process.argv.slice'),
      'contents.ts must not call process.argv.slice — use parseArgs from common.ts instead',
    )
  })
})

describe('refactor: research.ts uses common.ts helpers', () => {
  it('research.ts does not contain raw console.log(JSON.stringify(', () => {
    const src = readFileSync(resolve(__dirname, '../research.ts'), 'utf8')
    assert.ok(
      !src.includes('console.log(JSON.stringify('),
      'research.ts must not call console.log(JSON.stringify() directly — use executeAndPrint from common.ts instead',
    )
  })

  it('research.ts does not manually parse process.argv', () => {
    const src = readFileSync(resolve(__dirname, '../research.ts'), 'utf8')
    assert.ok(
      !src.includes('process.argv.slice'),
      'research.ts must not call process.argv.slice — use parseArgs from common.ts instead',
    )
  })
})
